{
  "mode": "method",
  "tests": [
    {
      "name": "valid_account_creation_email",
      "input": {
        "template": "R002",
        "user": {
          "name": "John Doe",
          "email": "john.doe@example.com"
        }
      },
      "output": "<html><body><h1>Welcome, John Doe!</h1><p>Your account has been created successfully.</p></body></html>",
      "notes": "Validates the account creation email template."
    },
    {
      "name": "valid_contact_email_support",
      "input": {
        "template": "R006",
        "user": {
          "name": "Jane Smith",
          "email": "jane.smith@example.com"
        },
        "message": "Need help with my account."
      },
      "output": "<html><body><h1>Contact Support</h1><p>Jane Smith has contacted support.</p><p>Message: Need help with my account.</p></body></html>",
      "notes": "Validates the contact email sent to support."
    },
    {
      "name": "valid_assessment_update_notification",
      "input": {
        "template": "R010",
        "user": {
          "name": "Alice Johnson",
          "email": "alice.johnson@example.com"
        },
        "assessment": "Assessment 1"
      },
      "output": "<html><body><h1>Assessment Update</h1><p>Your assessment 'Assessment 1' has been updated.</p></body></html>",
      "notes": "Validates the assessment update notification email."
    },
    {
      "name": "valid_assessment_complete_notification_user",
      "input": {
        "template": "R022",
        "user": {
          "name": "Bob Brown",
          "email": "bob.brown@example.com"
        },
        "assessment": "Assessment 2"
      },
      "output": "<html><body><h1>Assessment Complete</h1><p>Your assessment 'Assessment 2' is complete.</p></body></html>",
      "notes": "Validates the assessment complete notification for users."
    },
    {
      "name": "valid_assessment_complete_notification_agency",
      "input": {
        "template": "R026",
        "user": {
          "name": "Agency XYZ",
          "email": "agency@example.com"
        },
        "assessment": "Assessment 3"
      },
      "output": "<html><body><h1>Assessment Complete</h1><p>Agency XYZ, your assessment 'Assessment 3' is complete.</p></body></html>",
      "notes": "Validates the assessment complete notification for agencies."
    },
    {
      "name": "invalid_email_format",
      "input": {
        "template": "R002",
        "user": {
          "name": "Invalid User",
          "email": "invalid-email"
        }
      },
      "output": "Error: Invalid email format.",
      "notes": "Tests handling of invalid email formats."
    },
    {
      "name": "missing_template",
      "input": {
        "template": "R999",
        "user": {
          "name": "Test User",
          "email": "test.user@example.com"
        }
      },
      "output": "Error: Template not found.",
      "notes": "Tests behavior when a non-existent template is requested."
    },
    {
      "name": "empty_user_data",
      "input": {
        "template": "R002",
        "user": {}
      },
      "output": "Error: User data is required.",
      "notes": "Tests handling of missing user data."
    }
  ],
